import{_ as t,c as o,o as r,ae as a}from"./chunks/framework.Cqi9LMMK.js";const m=JSON.parse('{"title":"Export collections","description":"","frontmatter":{"title":"Export collections"},"headers":[],"relativePath":"network/export.md","filePath":"network/export.md"}'),s={name:"network/export.md"};function n(i,e,l,h,d,c){return r(),o("div",null,[...e[0]||(e[0]=[a('<h1 id="export-collection" tabindex="-1">Export Collection <a class="header-anchor" href="#export-collection" aria-label="Permalink to &quot;Export Collection&quot;">​</a></h1><p>On the <strong>Network</strong> tab you can save the captured requests as a <strong>Postman collection</strong> file (API description format compatible with Postman and many other clients). Useful to replay flows, share with teammates, or import into another testing tool.</p><p>What enters the list and data visibility limits are covered in <a href="/docs/network/general.html">Working with requests</a>.</p><hr><h2 id="where-the-command-lives" tabindex="-1">Where the command lives <a class="header-anchor" href="#where-the-command-lives" aria-label="Permalink to &quot;Where the command lives&quot;">​</a></h2><p><strong>Export Collection</strong> sits on the <strong>Network</strong> toolbar (near search and filters — on narrow layouts it may move but the action is the same).</p><p>The tooltip notes that the <strong>currently filtered</strong> set is exported.</p><p>The button is <strong>disabled</strong> while the filtered list is empty.</p><hr><h2 id="what-gets-exported" tabindex="-1">What gets exported <a class="header-anchor" href="#what-gets-exported" aria-label="Permalink to &quot;What gets exported&quot;">​</a></h2><p>The file includes <strong>only rows visible</strong> in the table with <strong>Search</strong> and active modes applied (path, method, status, keys/values in bodies, etc.). It is not necessarily the full history buffer: filters narrow the export.</p><p>For each included row the collection defines a request with:</p><ul><li><strong>method</strong> and <strong>URL</strong> (address components and query when present);</li><li><strong>request headers</strong> stored by the inspector (pseudo headers starting with <code>:</code> are omitted; for <strong>multipart</strong> bodies the content-type line may be skipped on purpose to avoid clashing with Postman <strong>form-data</strong> mode);</li><li><strong>request body</strong> when captured: raw text (with JSON language hint where applicable) or <strong>form-data</strong> fields, including file-part markers (binary files are not embedded — names or placeholders only, as usual for export without real attachments).</li></ul><p><strong>Server responses</strong> are <strong>not</strong> embedded — export describes <strong>outgoing</strong> requests you can replay from a client.</p><p>Item names follow the short label shown in the Network list.</p><hr><h2 id="file-on-disk" tabindex="-1">File on disk <a class="header-anchor" href="#file-on-disk" aria-label="Permalink to &quot;File on disk&quot;">​</a></h2><p>After <strong>Export Collection</strong> the browser offers a <strong>JSON</strong> download with a Postman-style name (spaces in the default title often become underscores).</p><p>Open it in <strong>Postman</strong> via collection import or in an editor to inspect structure.</p><hr><h2 id="caveats" tabindex="-1">Caveats <a class="header-anchor" href="#caveats" aria-label="Permalink to &quot;Caveats&quot;">​</a></h2><ul><li>Only <strong>headers and bodies the inspector could read</strong> appear in the export (CORS, truncated bodies, opaque binary).</li><li>Rows with <strong>network errors</strong> or partial data can still export if they remain in the filtered list — validate before reuse.</li><li><strong>Replaying</strong> from Postman may differ from the browser because of cookies, tokens, ambient headers, and environment — adjust after import if needed.</li></ul><hr><h2 id="see-also" tabindex="-1">See also <a class="header-anchor" href="#see-also" aria-label="Permalink to &quot;See also&quot;">​</a></h2><ul><li><a href="/docs/network/general.html">Working with requests</a></li><li><a href="/docs/network/traffic.html">Traffic interception</a></li></ul>',25)])])}const g=t(s,[["render",n]]);export{m as __pageData,g as default};
